-- 0011_add_orphan_tables.sql
-- Tables that existed in src/lib/db/schema/* but had no CREATE TABLE in drizzle/.
-- All statements use IF NOT EXISTS so this migration is idempotent:
--   - Neon prod (already has every table) => no-op
--   - fresh local install                 => creates all 16 tables
-- Generated by PR #10 from local DB introspection (+ 2 tables from schema).

