CREATE TABLE IF NOT EXISTS "bot_state" (
	"id" integer DEFAULT 1 NOT NULL,
	"last_nonce" integer NOT NULL,
	"updated_at" timestamp DEFAULT now() NOT NULL,
	CONSTRAINT "bot_state_pkey" PRIMARY KEY("id")
);

